BEGIN;
DELETE FROM "SwapCounterOffers" WHERE "SwapRequestId" IN (SELECT "Id" FROM "SwapRequests" WHERE "InitiatorShiftId" IN (SELECT "Id" FROM "Shifts" WHERE EXTRACT(YEAR FROM "Date")=2026) OR "CounterpartShiftId" IN (SELECT "Id" FROM "Shifts" WHERE EXTRACT(YEAR FROM "Date")=2026));
DELETE FROM "SwapRequests" WHERE "InitiatorShiftId" IN (SELECT "Id" FROM "Shifts" WHERE EXTRACT(YEAR FROM "Date")=2026) OR "CounterpartShiftId" IN (SELECT "Id" FROM "Shifts" WHERE EXTRACT(YEAR FROM "Date")=2026);
DELETE FROM "Shifts" WHERE EXTRACT(YEAR FROM "Date")=2026;
COMMIT;